"use client";

import type { ReactNode, CSSProperties, SVGProps, ComponentProps } from "react";
import { Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
} from "@/components/ui/dropdown-menu";

export type ButtonVariant =
  | "default"
  | "outline"
  | "secondary"
  | "ghost"
  | "destructive"
  | "link";

export type ButtonSize = "default" | "xs" | "sm" | "lg" | "icon";

export interface ActionProps {
  label?: ReactNode;
  variant?: ButtonVariant;
  disabled?: boolean;
  loading?: boolean;
  buttonProps?: ComponentProps<typeof Button>;
  onClick?: () => void;
  renderLabel?: (label: ReactNode, action: ActionProps) => ReactNode;
}

export type DropdownPosition = "top" | "tl" | "tr" | "bottom" | "bl" | "br";

export interface SActionGroupProps {
  actions: ActionProps[];
  max?: number;
  size?: ButtonSize;
  moreVariant?: ButtonVariant;
  moreButtonProps?: ComponentProps<typeof Button>;
  dropdownContentProps?: ComponentProps<typeof DropdownMenuContent>;
  dropdownPosition?: DropdownPosition;
  dropdownLoading?: boolean;
  style?: CSSProperties;
  className?: string;
}

function IconMore(props: SVGProps<SVGSVGElement>) {
  return (
    <svg
      width="1em"
      height="1em"
      viewBox="0 0 12 12"
      fill="currentColor"
      xmlns="http://www.w3.org/2000/svg"
      {...props}
    >
      <path
        fillRule="evenodd"
        clipRule="evenodd"
        d="M2 5.25001C1.72386 5.25001 1.5 5.47387 1.5 5.75001L1.5 6.25001C1.5 6.52615 1.72386 6.75001 2 6.75001L2.5 6.75001C2.77614 6.75001 3 6.52615 3 6.25001V5.75001C3 5.47387 2.77614 5.25001 2.5 5.25001H2ZM5.75 5.25001C5.47386 5.25001 5.25 5.47387 5.25 5.75001V6.25001C5.25 6.52615 5.47386 6.75001 5.75 6.75001L6.25 6.75001C6.52614 6.75001 6.75 6.52615 6.75 6.25001V5.75001C6.75 5.47387 6.52614 5.25001 6.25 5.25001H5.75ZM9.5 5.25001C9.22386 5.25001 9 5.47387 9 5.75001V6.25001C9 6.52615 9.22386 6.75001 9.5 6.75001L10 6.75001C10.2761 6.75001 10.5 6.52615 10.5 6.25001V5.75001C10.5 5.47387 10.2761 5.25001 10 5.25001H9.5Z"
      />
    </svg>
  );
}

const handleClick = (onClick?: () => void) => {
  return (e: React.MouseEvent) => {
    if (!onClick || e.metaKey || e.ctrlKey) {
      return;
    }
    e.preventDefault();
    onClick();
  };
};

const positionMap: Record<
  DropdownPosition,
  { side: "top" | "bottom"; align: "start" | "center" | "end" }
> = {
  top: { side: "top", align: "center" },
  tl: { side: "top", align: "start" },
  tr: { side: "top", align: "end" },
  bottom: { side: "bottom", align: "center" },
  bl: { side: "bottom", align: "start" },
  br: { side: "bottom", align: "end" },
};

const sizeGapMap: Record<string, string> = {
  xs: "[&>*]:mr-2 [&>*:last-child]:mr-0",
  sm: "[&>*]:mr-2 [&>*:last-child]:mr-0",
  default: "[&>*]:mr-3 [&>*:last-child]:mr-0",
  lg: "[&>*]:mr-3 [&>*:last-child]:mr-0",
  icon: "[&>*]:mr-3 [&>*:last-child]:mr-0",
};

const iconSizeMap: Record<string, string> = {
  xs: "icon-xs",
  sm: "icon-sm",
  default: "icon",
  lg: "icon-lg",
  icon: "icon",
} as const;

function LoadingWrapper({
  loading,
  children,
  size,
}: {
  loading?: boolean;
  children: ReactNode;
  size?: ButtonSize;
}) {
  if (!loading) return <>{children}</>;

  const spinnerSize =
    size === "xs" || size === "sm" ? "size-3" : "size-4";

  return (
    <span className="relative inline-flex items-center">
      <span className="invisible">{children}</span>
      <span className="absolute inset-0 flex items-center justify-center">
        <Loader2 className={cn("animate-spin", spinnerSize)} />
      </span>
    </span>
  );
}

function DropdownLoadingOverlay({
  loading,
  children,
  size,
}: {
  loading: boolean;
  children: ReactNode;
  size?: ButtonSize;
}) {
  if (!loading) return <>{children}</>;

  const spinnerSize =
    size === "xs" || size === "sm" ? "size-3" : "size-4";

  return (
    <div className="relative">
      <div className="invisible">{children}</div>
      <div className="absolute inset-0 flex items-center justify-center">
        <Loader2 className={cn("animate-spin", spinnerSize)} />
      </div>
    </div>
  );
}

const SActionGroup = (props: SActionGroupProps) => {
  const {
    style,
    className,
    actions,
    max = 3,
    moreVariant = "outline",
    size = "default",
    moreButtonProps = {},
    dropdownContentProps = {},
    dropdownPosition = "bl",
    dropdownLoading = false,
  } = props;

  if (!Array.isArray(actions) || actions.length === 0) return null;

  const { side, align } = positionMap[dropdownPosition];

  return (
    <div
      className={cn("inline-flex items-center", sizeGapMap[size], className)}
      style={style}
    >
      {actions.map((action, index) => {
        if (index < max) {
          const render =
            typeof action.renderLabel === "function"
              ? action.renderLabel
              : (node: ReactNode) => node;

          const buttonNode = (
            <Button
              onClick={handleClick(action.onClick)}
              variant={action.variant ?? "outline"}
              size={size}
              disabled={action.disabled}
              {...(action.buttonProps || {})}
            >
              {action.label ?? ""}
            </Button>
          );

          return (
            <div key={index} className="inline-flex items-center">
              <LoadingWrapper loading={action.loading} size={size}>
                {render(buttonNode, action)}
              </LoadingWrapper>
            </div>
          );
        }

        if (index === max) {
          const list = actions.slice(index);

          return (
            <DropdownMenu key={index}>
              <DropdownMenuTrigger
                render={
                  <Button
                    variant={moreVariant}
                    size={iconSizeMap[size] as ButtonSize}
                    {...moreButtonProps}
                  />
                }
              >
                <IconMore />
              </DropdownMenuTrigger>
              <DropdownMenuContent
                side={side}
                align={align}
                {...dropdownContentProps}
              >
                <DropdownLoadingOverlay
                  loading={dropdownLoading}
                  size={size}
                >
                  {list.map((dropAction, dropIndex) => {
                    const itemContent =
                      dropAction.renderLabel?.(
                        dropAction.label,
                        dropAction
                      ) ?? dropAction.label;

                    const menuItem = (
                      <DropdownMenuItem
                        key={dropIndex}
                        disabled={dropAction.disabled}
                        onSelect={() => dropAction.onClick?.()}
                      >
                        {dropAction.loading ? (
                          <span className="inline-flex items-center gap-2">
                            <Loader2 className="size-4 animate-spin" />
                            {itemContent}
                          </span>
                        ) : (
                          itemContent
                        )}
                      </DropdownMenuItem>
                    );

                    return menuItem;
                  })}
                </DropdownLoadingOverlay>
              </DropdownMenuContent>
            </DropdownMenu>
          );
        }

        return null;
      })}
    </div>
  );
};

export default SActionGroup;
